+            project.path(),
+            r#"
+export default function(pi) {
+    pi.exec("ls");
+}
+"#,
+        );
+
+        let opts = DoctorOptions {
+            cwd: project.path(),
+            extension_path: Some("ext"),
+            policy_override: None,
+            fix: false,
+            only: None,
+        };
